-- =============================================================
-- CALENDARIO FISCAL SENIAT 2026 — Gaceta Oficial N° 43.273 (09/12/2025)
-- PA SNAT/2025/000091 (Sujetos Pasivos Especiales) y SNAT/2025/000093 (Pensiones)
-- Generado y verificado contra el escaneo de la gaceta. Idempotente.
-- =============================================================
create table if not exists public.calendario_fiscal (
  id bigserial primary key,
  fecha date not null,
  impuesto text not null,
  descripcion text not null,
  ambito text not null default 'especial',  -- 'especial' (solo sujetos pasivos especiales) | 'todos'
  terminales text not null                   -- últimos dígitos de RIF a los que aplica, ej '0' u '08'
);
create index if not exists idx_calfiscal_fecha on public.calendario_fiscal(fecha);
alter table public.calendario_fiscal enable row level security;
drop policy if exists calendario_lectura on public.calendario_fiscal;
create policy calendario_lectura on public.calendario_fiscal for select using (true); -- catálogo (como planes)

-- Recarga limpia del año 2026
delete from public.calendario_fiscal where fecha >= '2026-01-01' and fecha <= '2026-12-31';

select impuesto, count(*) as fechas from public.calendario_fiscal group by impuesto order by impuesto;
